```python
class MemoryGraph:
    def __init__(self):
        # Stores concepts as nodes with connections and occurrence counts
        self.nodes = {}
        self.edges = {}

    def add_concepts(self, concepts):
        """
        Add concepts extracted from the latest input.
        Creates or updates nodes and edges.
        """
        for concept in concepts:
            if concept not in self.nodes:
                self.nodes[concept] = {"count": 0, "connections": set()}
            self.nodes[concept]["count"] += 1

        # Create edges between concepts in the same input for relationship building
        for i, c1 in enumerate(concepts):
            for c2 in concepts[i+1:]:
                self._add_edge(c1, c2)

    def _add_edge(self, c1, c2):
        edge_key = tuple(sorted([c1, c2]))
        if edge_key not in self.edges:
            self.edges[edge_key] = 0
        self.edges[edge_key] += 1
        # Update node connections
        self.nodes[c1]["connections"].add(c2)
        self.nodes[c2]["connections"].add(c1)

    def get_strongest_connections(self, concept, top_n=3):
        """
        Return top_n concepts most strongly connected to the given concept.
        """
        connections = [(c2, self.edges.get(tuple(sorted([concept, c2])), 0)) for c2 in self.nodes.get(concept, {}).get("connections", [])]
        connections.sort(key=lambda x: x[1], reverse=True)
        return [c for c, _ in connections[:top_n]]

    def recall_related(self, concepts, top_n=5):
        """
        Given a list of concepts, recall related concepts weighted by edge strength.
        Useful for enriching responses with context.
        """
        related_scores = {}
        for concept in concepts:
            for connected in self.nodes.get(concept, {}).get("connections", []):
                weight = self.edges.get(tuple(sorted([concept, connected])), 0)
                related_scores[connected] = related_scores.get(connected, 0) + weight

        # Sort related concepts by accumulated score
        sorted_related = sorted(related_scores.items(), key=lambda x: x[1], reverse=True)
        return [concept for concept, _ in sorted_related[:top_n]]

    def dump_state(self):
        """
        For debugging: returns current graph state
        """
        return {
            "nodes": self.nodes,
            "edges": self.edges,
        }
